use std::env;
use std::fs;
use std::path::{Path, PathBuf};

use walkdir::WalkDir;

const KB_DIRS: &[&str] = &["core", "web", "node", "ecosystem"];

fn main() {
  let bundled_enabled = env::var_os("CARGO_FEATURE_BUNDLED_KB").is_some();
  let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR"));

  let out_dir = PathBuf::from(env::var("OUT_DIR").expect("OUT_DIR"));
  let out_file = out_dir.join("knowledge_base_generated.rs");

  if !bundled_enabled {
    let mut output = String::new();
    output.push_str("// @generated by build.rs - do not edit.\n");
    output.push_str("pub const KB_FILES: &[(&str, &str)] = &[];\n");
    fs::write(out_file, output).expect("write generated knowledge base list");
    return;
  }

  let mut files: Vec<String> = Vec::new();
  for dir in KB_DIRS {
    let dir_path = manifest_dir.join(dir);
    println!("cargo:rerun-if-changed={}", dir_path.display());
    collect_kb_files(&manifest_dir, &dir_path, &mut files);
  }

  files.sort();
  files.dedup();

  let mut output = String::new();
  output.push_str("// @generated by build.rs - do not edit.\n");
  output.push_str("pub const KB_FILES: &[(&str, &str)] = &[\n");
  for rel in files {
    output.push_str(&format!(
      "  ({0:?}, include_str!(concat!(env!(\"CARGO_MANIFEST_DIR\"), \"/{0}\"))),\n",
      rel
    ));
  }
  output.push_str("];\n");

  fs::write(out_file, output).expect("write generated knowledge base list");
}

fn collect_kb_files(manifest_dir: &Path, dir: &Path, out: &mut Vec<String>) {
  if !dir.exists() {
    return;
  }

  for entry in WalkDir::new(dir)
    .follow_links(false)
    .into_iter()
    .filter_map(Result::ok)
  {
    let path = entry.path();
    if !path.is_file() {
      continue;
    }

    let Some(ext) = path.extension().and_then(|s| s.to_str()) else {
      continue;
    };
    match ext.to_ascii_lowercase().as_str() {
      "yaml" | "yml" | "toml" => {}
      _ => continue,
    }

    println!("cargo:rerun-if-changed={}", path.display());
    let rel = path
      .strip_prefix(manifest_dir)
      .expect("knowledge base file under manifest dir");
    out.push(rel.to_string_lossy().replace('\\', "/"));
  }
}

